// Clean + truncate scraped content per source.
// Inputs (in order, from Merge multiplex):
//   [0] Firecrawl blog response
//   [1] Firecrawl pricing response
//   [2] Notion battlecard query response
// Output: a single item per competitor with normalised, truncated text + scrape_status flags.

const MAX_CHARS = 2000;

const stripNoise = (s) => String(s || '')
  .replace(/<\/?[^>]+(>|$)/g, ' ')          // strip HTML tags
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1') // unwrap markdown links
  .replace(/!\[[^\]]*\]\([^)]+\)/g, '')    // drop images
  .replace(/[\u200B-\u200D\uFEFF]/g, '')   // zero-width chars
  .replace(/\s+/g, ' ')
  .trim();

const truncate = (s) => s.length > MAX_CHARS ? s.slice(0, MAX_CHARS) + '…' : s;

const extractFirecrawl = (resp) => {
  if (!resp || resp.success === false) return { ok: false, text: '', error: resp?.error || 'no_response' };
  const md = resp?.data?.markdown || resp?.markdown || resp?.data?.content || '';
  if (!md) return { ok: false, text: '', error: 'empty_markdown' };
  return { ok: true, text: truncate(stripNoise(md)) };
};

const extractNotion = (resp) => {
  if (!resp || resp.object === 'error') return { ok: false, text: '', error: resp?.message || 'notion_error' };
  const page = (resp.results || [])[0];
  if (!page) return { ok: false, text: '', error: 'battlecard_not_found' };
  // Naive flatten: pick title + plain-text from rich_text properties.
  const props = page.properties || {};
  const fields = ['Positioning', 'Strengths', 'Weaknesses', 'Objections', 'Win Stories'];
  const flat = fields
    .map(f => {
      const rt = props[f]?.rich_text || [];
      const txt = rt.map(r => r.plain_text).join(' ');
      return txt ? `${f.toUpperCase()}: ${txt}` : null;
    })
    .filter(Boolean)
    .join('\n\n');
  return { ok: true, text: truncate(stripNoise(flat)) };
};

const items = $input.all();
const competitor = $('Loop over competitors').item.json;
const runCfg = $('Set — Run config').first().json;

// items can be 1-3 long depending on Merge mode; map by index defensively
const blog      = extractFirecrawl(items[0]?.json);
const pricing   = extractFirecrawl(items[1]?.json);
const battlecard = extractNotion(items[2]?.json);

return [{
  json: {
    run_id: runCfg.run_id,
    week_of: runCfg.week_of,
    competitor_name: competitor.name,
    competitor_slug: competitor.slug,
    sources: {
      blog:       { ok: blog.ok,       text: blog.text,       error: blog.error || null,       url: competitor.blog_url },
      pricing:    { ok: pricing.ok,    text: pricing.text,    error: pricing.error || null,    url: competitor.pricing_url },
      battlecard: { ok: battlecard.ok, text: battlecard.text, error: battlecard.error || null, url: null }
    },
    scrape_status: {
      blog_ok: blog.ok,
      pricing_ok: pricing.ok,
      battlecard_ok: battlecard.ok,
      any_failed: !blog.ok || !pricing.ok || !battlecard.ok
    },
    scraped_at: new Date().toISOString()
  }
}];

