// Parse Claude classification, validate schema, set fallback on failure.
// Inputs from previous node: { content: [{type:'text', text:'<json>'}], ...} OR error envelope.

const priorityValid = new Set(['HIGH','MEDIUM','LOW']);
const classValid = new Set(['pricing_change','feature_launch','hire','funding','vertical_expansion','customer_departure','competitive_move','other']);

const llm = $json;        // anthropic response (or error)
const upstream = $('Code — clean + truncate').item.json;

let parsed = null;
let parseError = null;

try {
  const text = llm?.content?.[0]?.text;
  if (!text) throw new Error('no_content_in_anthropic_response');
  parsed = JSON.parse(text);
} catch (e) {
  parseError = e.message;
}

// Validate
if (parsed) {
  if (!priorityValid.has(parsed.priority_tier)) parsed.priority_tier = 'LOW';
  if (typeof parsed.confidence !== 'number' || parsed.confidence < 0 || parsed.confidence > 100) parsed.confidence = 0;
  if (!Array.isArray(parsed.signals)) parsed.signals = [];
  parsed.signals = parsed.signals.filter(s => s && s.headline && s.evidence && classValid.has(s.signal_class));
}

// Fallback for total failure: mark UNKNOWN priority, retain raw upstream so we can still write a low-confidence row.
const fallback = {
  signals: [],
  priority_tier: 'UNKNOWN',
  summary: null,
  confidence: 0,
  notes: parseError ? `parse_failed:${parseError}` : 'unknown_failure'
};

const result = parsed || fallback;

// Choose representative signal_type for the DB row (must satisfy CHECK constraint).
// Heuristic: if pricing source had content and any signal is pricing_change → 'pricing'; else 'blog'.
let signalType = 'blog';
const sigClasses = (result.signals || []).map(s => s.signal_class);
if (sigClasses.includes('pricing_change') && upstream.sources.pricing.ok) signalType = 'pricing';
else if (sigClasses.includes('feature_launch')) signalType = 'feature';
else if (sigClasses.includes('hire')) signalType = 'job_posting';
else if (sigClasses.includes('funding')) signalType = 'news';

// Build the content_raw payload (concatenated sources) and content_summary (LLM summary or first headline).
const content_raw = [
  upstream.sources.blog.ok       ? `[BLOG]\n${upstream.sources.blog.text}` : null,
  upstream.sources.pricing.ok    ? `[PRICING]\n${upstream.sources.pricing.text}` : null,
  upstream.sources.battlecard.ok ? `[BATTLECARD]\n${upstream.sources.battlecard.text}` : null
].filter(Boolean).join('\n\n');

const content_summary = result.summary || (result.signals?.[0]?.headline ?? null);

return [{
  json: {
    run_id: upstream.run_id,
    week_of: upstream.week_of,
    competitor_name: upstream.competitor_name,
    competitor_slug: upstream.competitor_slug,
    signal_type: signalType,
    priority_tier: result.priority_tier,
    confidence_score: result.confidence,
    content_raw,
    content_summary,
    signals: result.signals,
    notes: result.notes,
    source_url: upstream.sources.blog.url,
    scraped_at: upstream.scraped_at,
    scrape_status: upstream.scrape_status,
    parse_error: parseError
  }
}];

