// Build the prompt input for digest synthesis. Compress per-competitor classifications
// into a single signals_this_week array, plus a list of failed scrapes.

const agg = $json;
const names = agg.competitor_name || [];
const tiers = agg.priority_tier || [];
const summaries = agg.content_summary || [];
const signalsArr = agg.signals || [];
const statuses = agg.scrape_status || [];
const urls = agg.source_url || [];
const scraped = agg.scraped_at || [];
const signalTypes = agg.signal_type || [];
const confidences = agg.confidence_score || [];

const signals_this_week = [];
const failed_competitors = [];

for (let i = 0; i < names.length; i++) {
  const status = statuses[i] || {};
  if (status.any_failed && !status.blog_ok && !status.pricing_ok) {
    failed_competitors.push(names[i]);
  }
  // Flatten classified sub-signals into the digest input
  const subs = Array.isArray(signalsArr[i]) ? signalsArr[i] : [];
  if (subs.length === 0 && summaries[i]) {
    signals_this_week.push({
      competitor_name: names[i],
      signal_type: signalTypes[i] || 'blog',
      headline: summaries[i],
      evidence: '',
      signal_class: 'other',
      priority_tier: tiers[i] || 'LOW',
      confidence: confidences[i] || 0,
      source_url: urls[i] || null,
      scraped_at: scraped[i] || null
    });
  } else {
    for (const s of subs) {
      signals_this_week.push({
        competitor_name: names[i],
        signal_type: signalTypes[i] || 'blog',
        headline: s.headline,
        evidence: s.evidence,
        signal_class: s.signal_class,
        priority_tier: tiers[i] || 'LOW',
        confidence: confidences[i] || 0,
        source_url: urls[i] || null,
        scraped_at: scraped[i] || null
      });
    }
  }
}

const runCfg = $('Set — Run config').first().json;

return [{
  json: {
    run_id: runCfg.run_id,
    week_of: runCfg.week_of,
    generated_at: runCfg.generated_at,
    competitors_monitored: ['Pigment','Anaplan','Planful','Drivetrain','Vena'],
    competitors_with_failed_scrapes: failed_competitors,
    signals_this_week,
    last_week_digest: null
  }
}];

